import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import Web3Service from "@screens/web3-development-service";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const Web3Development = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Web3 Development Company", link: null },
  ];

  const { data } = props;
  const fileUrl =
    data?.web3GameDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const validData = data?.allMetaJson?.nodes[0];
  const location = useLocation();
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Web3 development company building secure blockchain, DeFi, NFT, and dApp solutions to power decentralized digital innovation.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1600",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What skills are needed for Web3 ?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Web3 skills needed: Blockchain fundamentals, smart contracts (Solidity), dApp development, Web3 frameworks, cryptography basics, and security knowledge.",
            },
          },
          {
            "@type": "Question",
            name: "Which language is best for Web3?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Solidity is the best language for Web3, especially for building smart contracts on Ethereum and EVM-based blockchains.",
            },
          },
          {
            "@type": "Question",
            name: "What is Web3 used for? ",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Web3 is used to build decentralized apps, enable secure peer-to-peer transactions, power DeFi, NFTs, DAOs, and give users control over their data and assets.",
            },
          },
        ],
      },
    ],
  };
  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      />
      <BreadCrumbV2 items={breadcrumbLinks} />
      <Web3Service db={db} />
    </Layout_v2>
  );
};

export default Web3Development;

export const queryData = graphql`
  query MyQuery {
    web3GameDevImg: file(relativePath: { eq: "web3-game-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "web3-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
